  long = coalesce(excluded.long, public.activities.long),
  category = excluded.category,
  website = excluded.website,
  organiser_website = excluded.organiser_website,
  app_rating = excluded.app_rating,
  number_of_reviews = excluded.number_of_reviews,
  description = excluded.description,
  image_url = coalesce(excluded.image_url, public.activities.image_url),
  image_source_url = excluded.image_source_url,
  public_listing_status = 'published',
  updated_at = now();
